import Page from 'components/Page';
import React from 'react';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { newSubject, findSubjects, findForms, } from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
import CustomToolbarSelectSubject from "../components/CustomToolbarSelectSubject";
class SubjectsPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          form : 'nn',
          name : '',
          pass_mark:'',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          data: [],
          forms:[],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            findSubjects(obje_results.user.token).then((response) => {
                console.log('data-data', response.data);
                this.setState({
                    ...this.state,
                    data:response.data,
                });
            }).catch((respError) => {});
            findForms(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    forms:response.data,
                });
            }).catch((respError) => {});
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }

    isValidEmailAddress = (email) => {
        if (/^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,4}$/i.test(email)) {
            return true;
        }
        return false;
    }

    rerenderParentCallback = () => {
      findSubjects (this.state.xtoken).then((response) => {
        this.setState({
            ...this.state,
            data:response.data,
        });
      }).catch((respError) => {
      });
    }
    
    handleFormInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, form: v,});
    }
    handleSubjectNameInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, name: v,});
    }
    handleSubjectPassMarkInput = (event) => {
      const v = event.target.value;
      this.setState({...this.state, pass_mark: v,});
    }
    handleSaveChanges = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        newSubject(this.state.xtoken, this.state)
        .then((response) => {
            // console.log('so_far', response);
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    form : 'nn',
                    name : '',
                    class_teacher:'nn',
                    label:'',
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });

                this.forceUpdate();
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:true,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:true,
            });
            console.log('error', error);
        });
    }
    render() {
        const columns = [
            {
              name: 'Id',
              options: {
                display: false
              }
            },
            'Form',
            'Subject',
            'Label',
            'Pass Mark',
        ];

        const data2 = () => {
          let rtn = [];
          this.state.data.map(item => {
            rtn.push([
                item.id,
                item.flabel,
                item.name,
                item.label,
                item.pass_mark,
            ]);
          });
          return rtn;
        }
      
        const options = {
            filter: true,
            selectableRows: 'single',
            selectableRowsOnClick:true,
            filterType: 'dropdown',
            responsive: 'vertical',
            draggableColumns: {
              enabled: true
            },
            rowsPerPage: 5,
            selectToolbarPlacement: 'replace',
            customToolbarSelect: (selectedRows, displayData, setSelectedRows) => (
              <CustomToolbarSelectSubject rerenderParentCallback={this.rerenderParentCallback} selectedRows={selectedRows} displayData={displayData} setSelectedRows={setSelectedRows}  originalData={this.state.data} Xtoken={this.state.xtoken}/>
            ),
            downloadOptions: {
                filename: 'school-data-excel-format.csv',
                separator: ';',
                filterOptions: {
                  useDisplayedColumnsOnly: true,
                  useDisplayedRowsOnly: true,
                }
            },
            onDownload: (buildHead, buildBody, columns, data2) => {
              if (this.state.downloadFile) {
                let val= `${buildHead(columns)}${buildBody(data2)}`.trim();
                return val;
              }
      
              return false;
            },
            onRowSelectionChange: (currentRowsSelected, allRows, rowsSelected) => {
              // console.log('currentRowsSelected', currentRowsSelected);
            },
            onRowsDelete: rowsDeleted => {
              // console.log(rowsDeleted, 'were deleted!');
            },
            onChangePage: numberRows => {
              // console.log(numberRows);
            },
            onSearchChange: searchText => {
              // console.log(searchText);
            },
            onColumnSortChange: (column, direction) => {
              // console.log(column, direction);
            },
            onViewColumnsChange: (column, action) => {
              // console.log(column, action);
            },
            onFilterChange: (column, filters) => {
              // console.log(column, filters);
            },
            onCellClick: (cellIndex, rowIndex) => {
              // console.log(cellIndex, rowIndex);
            },
            onRowClick: (rowData, rowState) => {
              // console.log(rowData, rowState);
            },
        };
      return (
        <Page title="Enrollment - Subjects" breadcrumbs={[{ name: 'Subjects', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>Create Subject {this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Form *</Label>
                      <Input onChange={this.handleFormInput} value={this.state.form} defaultValue={this.state.form} type="select" name="frm">
                        <option value="nn" disabled={true}>Select form</option>
                        {this.state.forms.map((stt, idx) => (
                            <option value={stt.id}>{stt.name}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                  <FormGroup>
                      <Label for="exampleEmail">Subject name*</Label>
                      <Input onChange={this.handleSubjectNameInput}
                        type="text" 
                        value={this.state.name}
                        name="frm"
                        placeholder="e.g Biology"
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Pass Mark *</Label>
                      <Input onChange={this.handleSubjectPassMarkInput}
                        type="number" 
                        value={this.state.pass_mark}
                        name="frm"
                        placeholder=""
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>              
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup check row>
                      <Col sm={{ size: 10, offset: 2 }}>
                        <Button type="button" onClick={this.handleSaveChanges}>Add now</Button>
                      </Col>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>

          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardBody>
                    <MUIDataTable title={'Enrollment - Subjects'}
                    data={this.state.data.map(item => {
                      return [
                        item.id,
                        item.flabel,
                        item.name,
                        item.label,
                        item.pass_mark,
                      ]
                    })} columns={columns} options={options} />
                </CardBody>
              </Card>
            </Col>
          </Row>
    
        </Page>
      );
    }
}
export default SubjectsPage;
